solution:
let buku = { judul: "Belajar JavaScript Dasar", penulis: "Andi", tahun: 2024, tersedia: true };
console.log(buku.judul);
console.log(buku.penulis);
buku.tersedia = false;
console.log(buku);

verification.testCode:
assert(typeof buku === 'object' && buku !== null, 'buku harus berupa objek');
assert(buku.judul !== undefined, 'Objek harus memiliki properti judul');
assert(buku.penulis !== undefined, 'Objek harus memiliki properti penulis');
assert(buku.tahun !== undefined, 'Objek harus memiliki properti tahun');
assert(buku.tersedia === false, 'Properti tersedia harus false setelah diubah');
